{
  "summary": "This paper introduces Continual Knowledge Learning (CKL), a framework for updating language models with new knowledge while preserving previously learned, time-invariant information. It proposes a novel benchmark suite and metric (FUAR) to evaluate forgetting and acquisition, and compares several continual learning methods, finding parameter-expansion approaches most effective but with memory trade-offs.",
  "strengths": [
    {
      "point": "Novel problem formulation addressing continual knowledge updating in LMs",
      "evidence": "CKL is defined as a new continual learning problem with a focus on preserving invariant knowledge while acquiring updated and new knowledge."
    },
    {
      "point": "Comprehensive benchmark and metric design",
      "evidence": "The paper constructs INVARIANT, UPDATED, and NEW LAMA datasets and proposes the FUAR metric to quantify the trade-off between forgetting and acquisition."
    },
    {
      "point": "Extensive empirical evaluation across methods and architectures",
      "evidence": "Evaluations include regularization, rehearsal, and parameter-expansion methods on encoder-decoder and decoder-only LMs, with multi-phase CKL and downstream task analyses."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent knowledge editing methods",
      "evidence": "No discussion or empirical comparison to MEND, ROME, MEMIT, which also aim to update model knowledge with minimal forgetting."
    },
    {
      "point": "Insufficient analysis and justification of dataset construction",
      "evidence": "No quantitative statistics on topical diversity or domain coverage of the news corpus \(D_1\), limiting understanding of benchmark representativeness."
    },
    {
      "point": "Limited baselines in continual learning evaluation",
      "evidence": "Only RecAdam and Mix-Review are evaluated, missing well-established methods like EWC, L2 regularization, or advanced replay strategies."
    },
    {
      "point": "Missing sensitivity and interpretability analysis of FUAR metric",
      "evidence": "No ablation or case studies demonstrating FUAR’s robustness or how to interpret low values in different scenarios."
    },
    {
      "point": "No ablation studies on design choices of the Modular parameter-expansion method",
      "evidence": "Critical factors like module size, architecture, initialization, and integration with base LM are not analyzed."
    },
    {
      "point": "Reproducibility concerns due to missing hyperparameter details and resource release",
      "evidence": "Details on continued pretraining hyperparameters are absent, and no mention of code, data, or benchmark release."
    },
    {
      "point": "Ambiguous definitions and examples for key concepts",
      "evidence": "The notion of time-invariant knowledge is not clearly defined or exemplified, complicating dataset split validity and metric interpretation."
    },
    {
      "point": "Limited experimental scope and generalizability",
      "evidence": "Experiments focus solely on English and news domain, with no exploration of other languages or knowledge types."
    },
    {
      "point": "No systematic study on data size ratio impact between \(D_0\) and \(D_1\)",
      "evidence": "The influence of varying dataset size ratios on forgetting and acquisition is not investigated."
    },
    {
      "point": "Insufficient detail on multi-phase CKL experimental setup",
      "evidence": "Lack of description on phase splitting, sequencing, and parameter management hinders reproducibility."
    },
    {
      "point": "Absence of human or qualitative evaluation of knowledge updates",
      "evidence": "Evaluation relies solely on automated cloze tasks and FUAR metric without qualitative or human assessment."
    },
    {
      "point": "No discussion on handling conflicting or ambiguous knowledge",
      "evidence": "CKL assumes clear knowledge distinctions but does not address real-world conflicts or ambiguities."
    },
    {
      "point": "Memory inefficiency of parameter-expansion methods not addressed",
      "evidence": "No proposed or evaluated strategies to mitigate growing memory footprint across multiple CKL phases."
    },
    {
      "point": "Downstream evaluation lacks task details and analysis",
      "evidence": "Tasks and datasets used are unspecified, and relation to updated knowledge is unclear."
    }
  ],
  "questions": [
    {
      "question": "How does CKL compare empirically and conceptually to recent knowledge editing methods like MEND, ROME, or MEMIT?",
      "motivation": "Understanding this would clarify CKL’s novelty and practical advantages over existing fine-grained knowledge update approaches."
    },
    {
      "question": "How sensitive and reliable is the FUAR metric under different forgetting and acquisition scenarios?",
      "motivation": "Ensuring FUAR accurately reflects continual learning performance is critical for fair model comparison and future research."
    },
    {
      "question": "What are the effects of varying the size ratio between original and new knowledge datasets on CKL performance?",
      "motivation": "This informs dataset construction and method applicability in real-world settings with diverse data scales."
    },
    {
      "question": "Can the Modular parameter-expansion method be adapted efficiently to other LM architectures and settings?",
      "motivation": "Ablations on design choices would guide broader adoption and optimization of this promising approach."
    },
    {
      "question": "How can CKL methods be extended to handle conflicting, ambiguous, or multi-perspective knowledge updates?",
      "motivation": "Addressing this is essential for robust, real-world continual knowledge updating."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
